// Decoding/Encoding helpers as per Gemini SDK requirement
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const App: React.FC = () => {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [transcription, setTranscription] = useState<string>("");
  const [aiResponse, setAiResponse] = useState<string>("");
  const [isListening, setIsListening] = useState(false);
  const [isSearchingScriptures, setIsSearchingScriptures] = useState(false);
  const [scriptureResults, setScriptureResults] = useState<ScriptureResult | null>(null);

  const [protocols, setProtocols] = useState<Protocol[]>(() => {
    const saved = localStorage.getItem('brahmastra_protocols');
    return saved ? JSON.parse(saved) : [
      { id: '1', phrase: 'Initiate Red Protocol', action: 'Set all systems to maximum alert and scan local perimeter.' },
      { id: '2', phrase: 'Dharma Check', action: 'Quote a relevant shloka from Bhagavad Gita for the current situation.' }
    ];
  });

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);

  useEffect(() => {
    localStorage.setItem('brahmastra_protocols', JSON.stringify(protocols));
  }, [protocols]);

  const getSystemInstruction = () => {
    let instruction = SYSTEM_INSTRUCTION;
    if (protocols.length > 0) {
      instruction += "\n\nCUSTOM USER PROTOCOLS:\n";
      protocols.forEach(p => {
        instruction += `- If the user says "${p.phrase}", you must: ${p.action}\n`;
      });
    }
    return instruction;
  };

  const startSession = async () => {
    if (status === ConnectionStatus.CONNECTED) return;

    setStatus(ConnectionStatus.CONNECTING);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      }
      if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: getSystemInstruction(),
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } },
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            setIsListening(true);

            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              setTranscription(prev => prev + message.serverContent?.inputTranscription?.text);
            }
            if (message.serverContent?.outputTranscription) {
              setAiResponse(prev => prev + message.serverContent?.outputTranscription?.text);
            }
            if (message.serverContent?.turnComplete) {
              setTranscription("");
              setAiResponse("");
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputAudioContextRef.current) {
              const ctx = outputAudioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error("Live Error", e);
            setStatus(ConnectionStatus.ERROR);
          },
          onclose: () => {
            setStatus(ConnectionStatus.DISCONNECTED);
            setIsListening(false);
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsListening(false);
  };

  const addProtocol = (p: Omit<Protocol, 'id'>) => {
    const newProtocol = { ...p, id: Date.now().toString() };
    setProtocols([...protocols, newProtocol]);
  };

  const removeProtocol = (id: string) => {
    setProtocols(protocols.filter(p => p.id !== id));
  };

  const searchScriptures = async (query: string) => {
    setIsSearchingScriptures(true);
    setScriptureResults(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `I need information from Hindu scriptures (Mahabharat, Ramayana, Geeta, Puranas, or Vedas) regarding this query: "${query}". 
        Please provide:
        1. Original Shloka (if applicable)
        2. Hindi/English Translation
        3. A detailed Hinglish explanation in the style of BRAHMASTRA (sophisticated JARVIS tone).
        4. The specific source book and chapter/verse.`,
        config: {
          tools: [{ googleSearch: {} }]
        }
      });

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const urls = groundingChunks.map((chunk: any) => ({
        web: {
          uri: chunk.web?.uri || '',
          title: chunk.web?.title || 'Scripture Reference'
        }
      }));

      // Basic parsing of the model's text response for display
      setScriptureResults({
        explanation: response.text || "Scanning complete. No specific data found.",
        source: "Deep Scriptural Repositories",
        urls: urls
      });
    } catch (error) {
      console.error("Scripture search error:", error);
      setScriptureResults({
        explanation: "Error accessing scriptural archives. Please check system integrity.",
        source: "System Error",
        urls: []
      });
    } finally {
      setIsSearchingScriptures(false);
    }
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-slate-950 text-cyan-50 selection:bg-cyan-500/30">
      <HUD 
        status={status} 
        isListening={isListening} 
        transcription={transcription}
        aiResponse={aiResponse}
        protocols={protocols}
        onAddProtocol={addProtocol}
        onRemoveProtocol={removeProtocol}
        onTogglePower={status === ConnectionStatus.CONNECTED ? stopSession : startSession}
        onSearchScriptures={searchScriptures}
        scriptureResults={scriptureResults}
        isSearchingScriptures={isSearchingScriptures}
      />
    </div>
  );
};

