// Decoding/Encoding helpers
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const App: React.FC = () => {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [transcription, setTranscription] = useState<string>("");
  const [aiResponse, setAiResponse] = useState<string>("");
  const [isListening, setIsListening] = useState(false);
  const [isSearchingScriptures, setIsSearchingScriptures] = useState(false);
  const [scriptureResults, setScriptureResults] = useState<ScriptureResult | null>(null);

  // Simulated System State
  const [commandLogs, setCommandLogs] = useState<string[]>(["Core systems initialized... ready for boss commands."]);
  const [systemStats, setSystemStats] = useState({
    power: 88,
    memory: 45,
    logic: 95
  });

  // Memory & Context Management
  const [memories, setMemories] = useState<string[]>(() => {
    const saved = localStorage.getItem('brahmastra_memories');
    return saved ? JSON.parse(saved) : ["Boss prefers Hinglish interaction.", "Admin access granted."];
  });

  const [protocols, setProtocols] = useState<Protocol[]>(() => {
    const saved = localStorage.getItem('brahmastra_protocols');
    return saved ? JSON.parse(saved) : [
      { id: '1', phrase: 'Initiate Red Protocol', action: 'Set all systems to maximum alert and scan local perimeter.' },
      { id: '2', phrase: 'Dharma Check', action: 'Quote a relevant shloka from Bhagavad Gita for the current situation.' }
    ];
  });

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);

  useEffect(() => {
    localStorage.setItem('brahmastra_protocols', JSON.stringify(protocols));
  }, [protocols]);

  useEffect(() => {
    localStorage.setItem('brahmastra_memories', JSON.stringify(memories));
  }, [memories]);

  const addLog = (msg: string) => {
    setCommandLogs(prev => [...prev.slice(-15), `> ${msg}`]);
  };

  const handleSystemCommand = (args: any) => {
    const { command, target, value } = args;
    addLog(`EXECUTING: ${command} on ${target} ${value ? `(${value})` : ''}`);

    // Simulate logic changes based on commands
    if (command === 'ADJUST_SETTING' && target === 'POWER_LEVEL') {
      const numVal = parseInt(value) || 100;
      setSystemStats(prev => ({ ...prev, power: numVal }));
    } else if (command === 'FILE_SCAN') {
      setSystemStats(prev => ({ ...prev, memory: Math.min(100, prev.memory + 5) }));
    } else if (command === 'SECURITY_LOCK') {
      addLog("SECURITY ENFORCED: ALL SECTORS LOCKED");
      setSystemStats(prev => ({ ...prev, logic: 100 }));
    }

    return "Command recognized and executed by BRAHMASTRA Admin Core, Sir.";
  };

  const getFullSystemInstruction = () => {
    let instruction = SYSTEM_INSTRUCTION_BASE;

    if (memories.length > 0) {
      instruction += "\n\nPAST CONTEXT & MEMORIES:\n";
      memories.forEach(m => {
        instruction += `- ${m}\n`;
      });
    }

    if (protocols.length > 0) {
      instruction += "\n\nCUSTOM USER PROTOCOLS:\n";
      protocols.forEach(p => {
        instruction += `- If the user says "${p.phrase}", you must: ${p.action}\n`;
      });
    }
    return instruction;
  };

  const startSession = async () => {
    if (status === ConnectionStatus.CONNECTED) return;

    setStatus(ConnectionStatus.CONNECTING);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      }
      if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: getFullSystemInstruction(),
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [SYSTEM_COMMAND_TOOL] }, { googleSearch: {} }],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } },
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            setIsListening(true);
            addLog("BRAHMASTRA CORE: ONLINE");

            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Tool Calls (Simulated PC Commands)
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'execute_system_command') {
                  const result = handleSystemCommand(fc.args);
                  sessionPromise.then(session => {
                    session.sendToolResponse({
                      functionResponses: [{ id: fc.id, name: fc.name, response: { result } }]
                    });
                  });
                }
              }
            }

            // Real-time Transcription
            if (message.serverContent?.inputTranscription) {
              setTranscription(prev => prev + message.serverContent?.inputTranscription?.text);
            }
            if (message.serverContent?.outputTranscription) {
              setAiResponse(prev => prev + message.serverContent?.outputTranscription?.text);
            }

            // Turn Completion & Auto-Memory Logic
            if (message.serverContent?.turnComplete) {
              // If the response contains "Remember that" or similar, we could programmatically extract it.
              // For now, let's keep it simple: we clear transcription but keep aiResponse for a few seconds.
              setTranscription("");
              setTimeout(() => setAiResponse(""), 5000);
            }

            // Audio Playback
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputAudioContextRef.current) {
              const ctx = outputAudioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            // Interruption Handling
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setAiResponse("[Interrupted by Boss]");
            }
          },
          onerror: (e) => {
            console.error("Live Error", e);
            setStatus(ConnectionStatus.ERROR);
            addLog("SYSTEM FAILURE: CONNECTION DROPPED");
          },
          onclose: () => {
            setStatus(ConnectionStatus.DISCONNECTED);
            setIsListening(false);
            addLog("SYSTEM STANDBY: BRAHMASTRA OFFLINE");
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsListening(false);
  };

  const addProtocol = (p: Omit<Protocol, 'id'>) => {
    const newProtocol = { ...p, id: Date.now().toString() };
    setProtocols([...protocols, newProtocol]);
    addLog(`PROTOCOL DEPLOYED: ${p.phrase}`);
  };

  const removeProtocol = (id: string) => {
    setProtocols(protocols.filter(p => p.id !== id));
  };

  const searchScriptures = async (query: string) => {
    setIsSearchingScriptures(true);
    setScriptureResults(null);
    addLog(`DECODING SCRIPTURE: ${query}`);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Reference Hindu scriptures (Mahabharat, Ramayana, Geeta, Puranas, or Vedas) for: "${query}". 
        Provide original Shloka, Translation, and a Hinglish explanation in BRAHMASTRA style.`,
        config: {
          tools: [{ googleSearch: {} }]
        }
      });

      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const urls = chunks.map((c: any) => ({
        web: { uri: c.web?.uri || '', title: c.web?.title || 'Source' }
      }));

      setScriptureResults({
        explanation: response.text || "Data corrupted or missing.",
        source: "Vedic Archives",
        urls: urls
      });
      addLog("SCRIPTURE RETRIEVAL: SUCCESSFUL");
    } catch (error) {
      console.error(error);
      addLog("SCRIPTURE RETRIEVAL: ERROR");
    } finally {
      setIsSearchingScriptures(false);
    }
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-slate-950 text-cyan-50 selection:bg-cyan-500/30">
      <HUD 
        status={status} 
        isListening={isListening} 
        transcription={transcription}
        aiResponse={aiResponse}
        protocols={protocols}
        onAddProtocol={addProtocol}
        onRemoveProtocol={removeProtocol}
        onTogglePower={status === ConnectionStatus.CONNECTED ? stopSession : startSession}
        onSearchScriptures={searchScriptures}
        scriptureResults={scriptureResults}
        isSearchingScriptures={isSearchingScriptures}
        commandLogs={commandLogs}
        systemStats={systemStats}
        memoryCount={memories.length}
      />
    </div>
  );
};

