                  const result = handleSystemCommand(fc.args);
                  sessionPromise.then(session => session.sendToolResponse({
                    functionResponses: [{ id: fc.id, name: fc.name, response: { result } }]
                  }));
                }
              }
            }
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscription(prev => prev + text);
              currentTurnUser.current += text;
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setAiResponse(prev => prev + text);
              currentTurnAssistant.current += text;
            }
            if (message.serverContent?.turnComplete) {
              if (currentTurnUser.current.trim() || currentTurnAssistant.current.trim()) {
                const newHistoryEntries: Message[] = [];
                if (currentTurnUser.current.trim()) newHistoryEntries.push({ role: 'user', content: currentTurnUser.current.trim(), timestamp: Date.now() });
                if (currentTurnAssistant.current.trim()) newHistoryEntries.push({ role: 'assistant', content: currentTurnAssistant.current.trim(), timestamp: Date.now() });
                setHistory(prev => [...prev, ...newHistoryEntries]);
              }
              currentTurnUser.current = "";
              currentTurnAssistant.current = "";
              setTranscription("");
              setTimeout(() => setAiResponse(""), 4000);
            }
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputAudioContextRef.current && gainNodeRef.current) {
              const ctx = outputAudioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(gainNodeRef.current);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => { setStatus(ConnectionStatus.ERROR); addLog("ERR: LINK TERMINATED."); },
          onclose: (e: any) => { setStatus(ConnectionStatus.DISCONNECTED); setIsListening(false); addLog("SYNC: SESSION TERMINATED."); nextStartTimeRef.current = 0; }
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) { setStatus(ConnectionStatus.ERROR); addLog("ERR: AUTHENTICATION FAILURE."); }
  };

  const stopSession = () => {
    if (sessionRef.current) { sessionRef.current.close(); sessionRef.current = null; }
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsListening(false);
  };

  const searchScriptures = async (query: string) => {
    setIsSearchingScriptures(true);
    setScriptureResults(null);
    addLog(`SCAN: ACCESSING VEDIC DATABANKS -> ${query}`);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Reference Hindu scriptures for: "${query}". Provide Shloka and Hinglish explanation as BRAHMASTRA.`,
        config: { tools: [{ googleSearch: {} }] }
      });
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const urls = chunks.map((c: any) => ({ web: { uri: c.web?.uri || '', title: c.web?.title || 'Source' } }));
      setScriptureResults({ explanation: response.text || "No matches.", source: "Vedic Archives", urls: urls });
      addLog("SCAN: ANALYSIS COMPLETE.");
    } catch (error) { addLog("SCAN: ARCHIVE ACCESS DENIED."); } finally { setIsSearchingScriptures(false); }
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-slate-950 text-cyan-50 selection:bg-cyan-500/30">
      <HUD 
        status={status} 
        isListening={isListening} 
        isMuted={isMuted}
        theme={theme}
        onThemeChange={setTheme}
        onToggleMute={() => setIsMuted(!isMuted)}
        transcription={transcription}
        aiResponse={aiResponse}
        protocols={protocols}
        onAddProtocol={(p) => setProtocols([...protocols, { ...p, id: Date.now().toString() }])}
        onRemoveProtocol={(id) => setProtocols(protocols.filter(p => p.id !== id))}
        onTogglePower={status === ConnectionStatus.CONNECTED ? stopSession : startSession}
        onSearchScriptures={searchScriptures}
        scriptureResults={scriptureResults}
        isSearchingScriptures={isSearchingScriptures}
        commandLogs={commandLogs}
        systemStats={systemStats}
        memoryCount={memories.length}
        history={history}
        onClearHistory={clearHistory}
        processes={processes}
        onKillProcess={killProcessManually}
      />
    </div>
  );
};

