  }, [isMuted]);

  useEffect(() => {
    const interval = setInterval(() => {
      setSystemStats(prev => ({
        ...prev,
        cpu: Math.min(100, Math.max(0, prev.cpu + (Math.random() * 4 - 2))),
        memory: Math.min(100, Math.max(0, prev.memory + (Math.random() * 2 - 1))),
        logic: Math.min(100, Math.max(0, prev.logic + (Math.random() * 0.4 - 0.2)))
      }));
      setProcesses(prev => prev.map(p => ({
        ...p,
        cpu: Math.max(0, p.cpu + (Math.random() * 2 - 1)),
        memory: Math.max(10, p.memory + (Math.random() * 10 - 5))
      })));
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  const addLog = (msg: string) => {
    setCommandLogs(prev => [...prev.slice(-15), msg]);
  };

  const clearHistory = () => {
    setHistory([]);
    addLog("SYSTEM: Archives purged successfully.");
  };

  const downloadHistory = () => {
    if (history.length === 0) {
      addLog("WARN: No neural logs found for export.");
      return;
    }
    const logContent = history.map(msg => 
      `[${new Date(msg.timestamp).toLocaleString()}] ${msg.role.toUpperCase()}: ${msg.content}`
    ).join('\n\n');

    const blob = new Blob([`BRAHMASTRA SECURE LOG ARCHIVE\nGenerated: ${new Date().toLocaleString()}\n\n${logContent}`], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `BRAHMASTRA_ARCHIVE_${Date.now()}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    addLog("SUCCESS: Neural archive exported to primary disk.");
