  const killProcessManually = (pid: number) => {
    const p = processes.find(proc => proc.pid === pid);
    if (p) {
      setProcesses(prev => prev.filter(proc => proc.pid !== pid));
      addLog(`MANUAL_EXEC: Neutralized PID ${pid} (${p.name}).`);
    }
  };

  const handleSystemCommand = (args: any) => {
    const { command, target, value } = args;
    addLog(`EXEC: ${command} -> ${target} ${value ? `(${value})` : ''}`);

    let resultMessage = "Command processed successfully, Sir.";

    switch (command) {
      case 'ADJUST_SETTING':
        if (target === 'POWER_LEVEL') {
          const p = parseInt(value) || 100;
          setSystemStats(prev => ({ ...prev, power: p }));
          resultMessage = `Power distribution adjusted to ${p}%. Logic gates synchronized.`;
        }
        break;
      case 'SECURITY_LOCK':
        addLog("ALERT: ALL SECTORS LOCKED");
        setSystemStats(prev => ({ ...prev, logic: 100 }));
        resultMessage = "Global lockdown sequence complete. Perimeter secure. Dharma protocol engaged.";
        break;
      case 'OPEN_APP':
        addLog(`SYSTEM: Launching ${target} environment...`);
        const newProc: Process = { pid: Math.floor(Math.random() * 9000) + 1000, name: `${target.toLowerCase()}.exe`, cpu: 5.0, memory: 256, status: 'Running' };
        setProcesses(prev => [...prev, newProc]);
        resultMessage = `${target} has been initialized in your primary workspace, Boss. PID ${newProc.pid} is stable.`;
        break;
      case 'LIST_PROCESSES':
        addLog(`SCAN: Reading background tasks...`);
        resultMessage = `Sir, I've listed the primary active processes in the telemetry vault. ${processes.length} active threads detected.`;
        break;
      case 'KILL_PROCESS':
        addLog(`EXEC: Terminating ${target}...`);
        const pidToKill = parseInt(target);
        if (!isNaN(pidToKill)) {
          setProcesses(prev => prev.filter(p => p.pid !== pidToKill));
          resultMessage = `Bilkul Sir, process PID ${pidToKill} has been successfully neutralized.`;
        } else {
          setProcesses(prev => prev.filter(p => p.name.toLowerCase() !== target.toLowerCase()));
          resultMessage = `Bilkul Sir, ${target} has been successfully neutralized.`;
        }
        break;
      case 'MONITOR_RESOURCES':
        addLog(`TELEMETRY: CPU: ${systemStats.cpu.toFixed(1)}% | RAM: ${systemStats.memory.toFixed(1)}% | Logic: ${systemStats.logic.toFixed(1)}%`);
        resultMessage = `Current diagnostics show CPU at ${systemStats.cpu.toFixed(1)}% and memory usage at ${systemStats.memory.toFixed(1)}%, Sir. System integrity is at peak performance.`;
        break;
      default:
        addLog(`WARN: Unknown administrative protocol ${command}.`);
    }

    return resultMessage;
  };

  const getFullSystemInstruction = () => {
    let instruction = SYSTEM_INSTRUCTION_BASE;
    if (memories.length > 0) {
      instruction += "\n\nPAST CONTEXT & MEMORIES:\n" + memories.map(m => `- ${m}`).join('\n');
    }
    if (protocols.length > 0) {
      instruction += "\n\nCUSTOM USER PROTOCOLS:\n" + protocols.map(p => `- If user says "${p.phrase}": ${p.action}`).join('\n');
    }
    return instruction;
  };

  const startSession = async () => {
    if (status === ConnectionStatus.CONNECTED || status === ConnectionStatus.CONNECTING) return;
    setStatus(ConnectionStatus.CONNECTING);
    addLog("SYNC: INITIATING HANDSHAKE...");
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      if (!outputAudioContextRef.current) outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      if (!gainNodeRef.current) {
        gainNodeRef.current = outputAudioContextRef.current.createGain();
        gainNodeRef.current.connect(outputAudioContextRef.current.destination);
        gainNodeRef.current.gain.value = isMuted ? 0 : 1;
      }
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        config: {
          systemInstruction: getFullSystemInstruction(),
          responseModalities: ['AUDIO'],
          tools: [{ functionDeclarations: [SYSTEM_COMMAND_TOOL] }],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            setIsListening(true);
            addLog("SYNC: BRAHMASTRA ONLINE [v4.5.0]");
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' };
              sessionPromise.then(session => session.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'execute_system_command') {
                  const result = handleSystemCommand(fc.args);
                  sessionPromise.then(session => session.sendToolResponse({
                    functionResponses: [{ id: fc.id, name: fc.name, response: { result } }]
                  }));
                }
              }
            }
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscription(prev => prev + text);
              currentTurnUser.current += text;
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setAiResponse(prev => prev + text);
              currentTurnAssistant.current += text;
            }
            if (message.serverContent?.turnComplete) {
              if (currentTurnUser.current.trim() || currentTurnAssistant.current.trim()) {
                const newHistoryEntries: Message[] = [];
                if (currentTurnUser.current.trim()) newHistoryEntries.push({ role: 'user', content: currentTurnUser.current.trim(), timestamp: Date.now() });
                if (currentTurnAssistant.current.trim()) newHistoryEntries.push({ role: 'assistant', content: currentTurnAssistant.current.trim(), timestamp: Date.now() });
                setHistory(prev => [...prev, ...newHistoryEntries]);
              }
              currentTurnUser.current = "";
              currentTurnAssistant.current = "";
              setTranscription("");
              setTimeout(() => setAiResponse(""), 4000);
            }
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputAudioContextRef.current && gainNodeRef.current) {
              const ctx = outputAudioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(gainNodeRef.current);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => { setStatus(ConnectionStatus.ERROR); addLog("ERR: LINK TERMINATED."); },
          onclose: (e: any) => { setStatus(ConnectionStatus.DISCONNECTED); setIsListening(false); addLog("SYNC: SESSION TERMINATED."); nextStartTimeRef.current = 0; }
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) { setStatus(ConnectionStatus.ERROR); addLog("ERR: AUTHENTICATION FAILURE."); }
  };

  const stopSession = () => {
    if (sessionRef.current) { sessionRef.current.close(); sessionRef.current = null; }
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsListening(false);
  };

  const searchScriptures = async (query: string) => {
    setIsSearchingScriptures(true);
    setScriptureResults(null);
    addLog(`SCAN: ACCESSING VEDIC DATABANKS -> ${query}`);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Reference Hindu scriptures for: "${query}". Provide Shloka and Hinglish explanation as BRAHMASTRA.`,
        config: { tools: [{ googleSearch: {} }] }
      });
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const urls = chunks.map((c: any) => ({ web: { uri: c.web?.uri || '', title: c.web?.title || 'Source' } }));
      setScriptureResults({ explanation: response.text || "No matches.", source: "Vedic Archives", urls: urls });
      addLog("SCAN: ANALYSIS COMPLETE.");
    } catch (error) { addLog("SCAN: ARCHIVE ACCESS DENIED."); } finally { setIsSearchingScriptures(false); }
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-slate-950 text-cyan-50 selection:bg-cyan-500/30">
      <HUD 
        status={status} 
        isListening={isListening} 
        isMuted={isMuted}
        theme={theme}
        onThemeChange={setTheme}
        onToggleMute={() => setIsMuted(!isMuted)}
        transcription={transcription}
        aiResponse={aiResponse}
        protocols={protocols}
        onAddProtocol={(p) => setProtocols([...protocols, { ...p, id: Date.now().toString() }])}
        onRemoveProtocol={(id) => setProtocols(protocols.filter(p => p.id !== id))}
        onTogglePower={status === ConnectionStatus.CONNECTED ? stopSession : startSession}
        onSearchScriptures={searchScriptures}
        scriptureResults={scriptureResults}
        isSearchingScriptures={isSearchingScriptures}
        commandLogs={commandLogs}
        systemStats={systemStats}
        memoryCount={memories.length}
        history={history}
        onClearHistory={clearHistory}
        onDownloadHistory={downloadHistory}
        processes={processes}
        onKillProcess={killProcessManually}
      />
    </div>
  );
};

