  memoryCount: number;
  history: Message[];
  onClearHistory: () => void;
  onDownloadHistory: () => void;
  processes: Process[];
  onKillProcess: (pid: number) => void;
}

const HUD: React.FC<HUDProps> = ({ 
  status, isListening, isMuted, theme, onThemeChange, onToggleMute, transcription, aiResponse, 
  protocols, onAddProtocol, onRemoveProtocol, onTogglePower, onSearchScriptures, scriptureResults, 
  isSearchingScriptures, commandLogs, systemStats, memoryCount, history, onClearHistory, onDownloadHistory, processes, onKillProcess 
}) => {
  const [time, setTime] = useState(new Date().toLocaleTimeString());
  const [activeModal, setActiveModal] = useState<'Protocols' | 'Scriptures' | 'History' | 'Themes' | 'Telemetry' | null>(null);
  const [scriptureQuery, setScriptureQuery] = useState('');
  const [historySearch, setHistorySearch] = useState('');
  const [newPhrase, setNewPhrase] = useState('');
  const [newAction, setNewAction] = useState('');
  const [isSyncingDesktop, setIsSyncingDesktop] = useState(false);

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date().toLocaleTimeString()), 1000);
    return () => clearInterval(timer);
  }, []);

  const themeColors = useMemo(() => {
    switch(theme) {
      case 'Saffron': return { primary: 'orange-500', text: 'text-orange-400', border: 'border-orange-500', glow: 'rgba(249, 115, 22, 0.4)', gradient: 'from-orange-500 to-amber-600', bg: 'bg-orange-500' };
      case 'Emerald': return { primary: 'emerald-500', text: 'text-emerald-400', border: 'border-emerald-500', glow: 'rgba(16, 185, 129, 0.4)', gradient: 'from-emerald-500 to-teal-600', bg: 'bg-emerald-500' };
      default: return { primary: 'cyan-500', text: 'text-cyan-400', border: 'border-cyan-500', glow: 'rgba(6, 182, 212, 0.4)', gradient: 'from-cyan-400 to-blue-600', bg: 'bg-cyan-500' };
    }
  }, [theme]);

  const filteredHistory = useMemo(() => {
    if (!historySearch.trim()) return history;
    return history.filter(msg => msg.content.toLowerCase().includes(historySearch.toLowerCase()));
  }, [history, historySearch]);

  const handleDesktopSync = () => {
