      alert("BRAHMASTRA is ready for deployment. Please use your browser's 'Install' or 'Add to Home Screen' option for a standalone desktop experience.");
    }

    setIsSyncingDesktop(false);
  };

  const addLog = (msg: string) => {
    // Note: We use the local commandLogs if we had state, but here we just rely on parent's logs
