          { icon: 'History', label: 'Logs', type: 'History' },
        ].map(item => (
          <button key={item.type} onClick={() => setActiveModal(item.type as any)} className="group px-4 py-2 flex flex-col items-center gap-1 hover:bg-white/5 rounded-xl transition-all">
            <div className={`w-8 h-8 flex items-center justify-center rounded-lg border border-white/5 group-hover:${themeColors.border}/40 transition-colors`}>
               <div className={`w-4 h-4 ${themeColors.bg} opacity-40 group-hover:opacity-100 rounded-sm`}></div>
