const CACHE_NAME = 'brahmastra-v1';
const ASSETS = [
  './',
  './index.html',
  './manifest.json'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(ASSETS))
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => response || fetch(event.request))
  );
});

import React, { useState, useEffect, useMemo } from 'react';
import { ConnectionStatus, Protocol, ScriptureResult, Message, ThemeType, Process } from '../types';

interface HUDProps {
  status: ConnectionStatus;
  isListening: boolean;
  isMuted: boolean;
  theme: ThemeType;
  onThemeChange: (theme: ThemeType) => void;
  onToggleMute: () => void;
  transcription: string;
  aiResponse: string;
  protocols: Protocol[];
  onAddProtocol: (p: Omit<Protocol, 'id'>) => void;
  onRemoveProtocol: (id: string) => void;
  onTogglePower: () => void;
  onSearchScriptures: (query: string) => void;
  scriptureResults: ScriptureResult | null;
  isSearchingScriptures: boolean;
  commandLogs: string[];
  systemStats: { power: number; memory: number; logic: number; cpu: number };
  memoryCount: number;
  history: Message[];
  onClearHistory: () => void;
  onDownloadHistory: () => void;
  processes: Process[];
  onKillProcess: (pid: number) => void;
}

const HUD: React.FC<HUDProps> = ({ 
  status, isListening, isMuted, theme, onThemeChange, onToggleMute, transcription, aiResponse, 
  protocols, onAddProtocol, onRemoveProtocol, onTogglePower, onSearchScriptures, scriptureResults, 
  isSearchingScriptures, commandLogs, systemStats, memoryCount, history, onClearHistory, onDownloadHistory, processes, onKillProcess 
}) => {
  const [time, setTime] = useState(new Date().toLocaleTimeString());
  const [activeModal, setActiveModal] = useState<'Protocols' | 'Scriptures' | 'History' | 'Themes' | 'Telemetry' | null>(null);
  const [scriptureQuery, setScriptureQuery] = useState('');
