  const [installPrompt, setInstallPrompt] = useState<any>(null);

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date().toLocaleTimeString()), 1000);

    const handleInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleInstallPrompt);

    return () => {
      clearInterval(timer);
      window.removeEventListener('beforeinstallprompt', handleInstallPrompt);
    };
  }, []);

  const themeColors = useMemo(() => {
    switch(theme) {
      case 'Saffron': return { primary: 'orange-500', text: 'text-orange-400', border: 'border-orange-500', glow: 'rgba(249, 115, 22, 0.4)', gradient: 'from-orange-500 to-amber-600', bg: 'bg-orange-500' };
      case 'Emerald': return { primary: 'emerald-500', text: 'text-emerald-400', border: 'border-emerald-500', glow: 'rgba(16, 185, 129, 0.4)', gradient: 'from-emerald-500 to-teal-600', bg: 'bg-emerald-500' };
      default: return { primary: 'cyan-500', text: 'text-cyan-400', border: 'border-cyan-500', glow: 'rgba(6, 182, 212, 0.4)', gradient: 'from-cyan-400 to-blue-600', bg: 'bg-cyan-500' };
    }
  }, [theme]);

  const filteredHistory = useMemo(() => {
    if (!historySearch.trim()) return history;
    return history.filter(msg => msg.content.toLowerCase().includes(historySearch.toLowerCase()));
  }, [history, historySearch]);

  const handleDesktopSync = async () => {
    if (!installPrompt) {
      alert("BRAHMASTRA is optimized for standalone use. Use your browser menu to 'Install' or 'Add to Home Screen'.");
      return;
    }

    setIsSyncingDesktop(true);
    try {
      await installPrompt.prompt();
      const { outcome } = await installPrompt.userChoice;
      if (outcome === 'accepted') {
        setInstallPrompt(null);
      }
    } catch (err) {
      console.error('Installation error:', err);
    } finally {
      setIsSyncingDesktop(false);
    }
  };

  return (
    <div className="relative flex-1 p-8 overflow-hidden font-orbitron select-none">
      {/* Background FX */}
