        <div className={`text-[10px] ${themeColors.text} opacity-60 tracking-[0.4em] uppercase font-bold`}>System Architect</div>
        <div className="text-3xl font-black text-white tracking-tighter">BRAHMASTRA <span className={`text-[10px] bg-white/5 border ${themeColors.border}/20 px-2 py-1 rounded ml-2`}>v4.5.0-LTS</span></div>

        {installPrompt && (
          <button 
            onClick={handleDesktopSync}
            disabled={isSyncingDesktop}
