          >
            <div className={`w-2 h-2 rounded-full ${themeColors.bg} shadow-[0_0_8px_currentColor]`}></div>
            <span className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Deploy to Local Host</span>
            <svg className="w-4 h-4 text-white/40 group-hover:text-white transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
            </svg>
          </button>
        )}

        <div className="flex gap-4 items-center mt-3">
