    { pid: 9021, name: 'unresponsive_node.exe', cpu: 98.1, memory: 2048, status: 'Critical' },
  ]);

  const [theme, setTheme] = useState<ThemeType>(() => (localStorage.getItem('brahmastra_theme') as ThemeType) || 'Indigo');
  const [history, setHistory] = useState<Message[]>(() => JSON.parse(localStorage.getItem('brahmastra_history') || '[]'));
  const [protocols, setProtocols] = useState<Protocol[]>(() => JSON.parse(localStorage.getItem('brahmastra_protocols') || '[]'));

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);
  const gestureRecognizerRef = useRef<any>(null);
  const lastGestureTimeRef = useRef<number>(0);

  const addLog = useCallback((msg: string) => setCommandLogs(prev => [...prev.slice(-19), msg]), []);

  const stopAudio = useCallback(() => {
    for (const source of sourcesRef.current.values()) { try { source.stop(); } catch (e) {} sourcesRef.current.delete(source); }
    nextStartTimeRef.current = 0;
  }, []);

  const handleImageAnalysis = async (file: File) => {
    setIsAnalyzingImage(true);
    addLog(`SYSTEM: Scanning visual data package: ${file.name}...`);
    try {
      const reader = new FileReader();
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(file);
      });
      const base64 = await base64Promise;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: {
          parts: [
            { inlineData: { data: base64, mimeType: file.type } },
            { text: "Analyze this image with high-level military-grade sensors. Explain what you see in your Hinglish BRAHMASTRA persona." }
          ]
        }
      });

      const analysis = response.text || "Encryption failed. Unable to parse visual data.";
      setAiResponse(analysis);
      addLog("SYSTEM: Visual analysis complete. Report transmitted.");
    } catch (err) {
      console.error(err);
      addLog("CRITICAL: Vision sensor malfunction.");
    } finally {
      setIsAnalyzingImage(false);
    }
  };

  const checkVoiceProtocols = useCallback((text: string) => {
    const matched = protocols.find(p => text.toLowerCase().includes(p.phrase.toLowerCase()));
    if (matched && !protocolAlert) {
      setProtocolAlert(matched.phrase);
      addLog(`PROTOCOL: ${matched.phrase} ACTIVATED.`);
      setAiResponse(`Bilkul Sir. ${matched.action}`);
      setTimeout(() => setProtocolAlert(null), 5000);
    }
  }, [protocols, protocolAlert, addLog]);

  const connect = useCallback(async () => {
    if (sessionRef.current) return;
    setStatus(ConnectionStatus.CONNECTING);
    addLog("SYSTEM: Establishing secure encrypted channel...");

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      gainNodeRef.current = outputAudioContextRef.current.createGain();
      gainNodeRef.current.connect(outputAudioContextRef.current.destination);

      let location = null;
      try {
        const pos: any = await new Promise((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
        location = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
        addLog(`TELEMETRY: Location Locked - ${location.latitude.toFixed(4)}, ${location.longitude.toFixed(4)}`);
      } catch (e) {
        addLog("WARN: Geolocation link bypassed.");
      }

      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: SYSTEM_INSTRUCTION_BASE,
          tools: [{ googleMaps: {} }, { googleSearch: {} }, { functionDeclarations: [SYSTEM_COMMAND_TOOL, SEARCH_SCRIPTURES_TOOL] }],
          toolConfig: location ? { retrievalConfig: { latLng: location } } : undefined,
          outputAudioTranscription: {},
          inputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            setIsListening(true);
            addLog("SYSTEM: Uplink established. Brahmastra Online.");
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (isMuted) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(session => session.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
            sessionRef.current = { scriptProcessor };
          },
          onmessage: async (message: LiveServerMessage) => {
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(gainNodeRef.current!);
              source.onended = () => sourcesRef.current.delete(source);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscription(text);
              checkVoiceProtocols(text);
            }
            if (message.serverContent?.outputTranscription) setAiResponse(message.serverContent.outputTranscription.text);
            if (message.serverContent?.interrupted) stopAudio();
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                 addLog(`TOOL: Accessing ${fc.name}...`);
                 // Handle specific tools here if needed
              }
            }
          },
          onerror: () => setStatus(ConnectionStatus.ERROR),
          onclose: () => { setStatus(ConnectionStatus.DISCONNECTED); setIsListening(false); sessionRef.current = null; }
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) { setStatus(ConnectionStatus.ERROR); }
  }, [addLog, checkVoiceProtocols, isMuted, stopAudio]);

  useEffect(() => {
    localStorage.setItem('brahmastra_protocols', JSON.stringify(protocols));
    localStorage.setItem('brahmastra_history', JSON.stringify(history));
    localStorage.setItem('brahmastra_theme', theme);
  }, [protocols, history, theme]);

  return (
    <div className="h-screen w-screen bg-slate-950 overflow-hidden relative">
      {protocolAlert && (
        <div className="absolute inset-0 pointer-events-none z-[300] flex items-center justify-center">
           <div className="w-[120%] h-[120%] border-[20px] border-red-600/20 rounded-full animate-ping"></div>
           <div className="absolute top-1/4 text-red-500 font-black text-4xl animate-pulse tracking-[0.5em] uppercase">PROTOCOL ACTIVATED</div>
        </div>
      )}
      <HUD 
        status={status}
        isListening={isListening}
        isMuted={isMuted}
        theme={theme}
        onThemeChange={setTheme}
        onToggleMute={() => setIsMuted(prev => !prev)}
        transcription={transcription}
        aiResponse={aiResponse}
        protocols={protocols}
        onAddProtocol={(p) => setProtocols(prev => [...prev, { ...p, id: Date.now().toString() }])}
        onRemoveProtocol={(id) => setProtocols(prev => prev.filter(p => p.id !== id))}
        onTogglePower={() => status === ConnectionStatus.CONNECTED ? disconnect() : connect()}
        onSearchScriptures={() => {}} 
        scriptureResults={scriptureResults}
        isSearchingScriptures={isSearchingScriptures}
        commandLogs={commandLogs}
        systemStats={systemStats}
        memoryCount={0}
        history={history}
        onClearHistory={() => setHistory([])}
        onDownloadHistory={() => {}}
        processes={processes}
        onKillProcess={(pid) => setProcesses(prev => prev.filter(p => p.pid !== pid))}
        onImageUpload={handleImageAnalysis}
        isAnalyzingImage={isAnalyzingImage}
      />
    </div>
  );
};

