      setProtocolAlert(matched.phrase);
      addLog(`PROTOCOL: ${matched.phrase} ACTIVATED.`);
      setAiResponse(`Bilkul Sir. ${matched.action}`);
      setTimeout(() => setProtocolAlert(null), 5000);
