        isListening={isListening}
        isMuted={isMuted}
        theme={theme}
        onThemeChange={setTheme}
        onToggleMute={() => setIsMuted(prev => !prev)}
        transcription={transcription}
        aiResponse={aiResponse}
        protocols={protocols}
        onAddProtocol={(p) => setProtocols(prev => [...prev, { ...p, id: Date.now().toString() }])}
