import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ConnectionStatus, Protocol, ScriptureResult, Message, ThemeType, Process, CommandShortcut } from '../types';

interface HUDProps {
  status: ConnectionStatus;
  isListening: boolean;
  isMuted: boolean;
  theme: ThemeType;
  onThemeChange: (theme: ThemeType) => void;
  onToggleMute: () => void;
  transcription: string;
  aiResponse: string;
  protocols: Protocol[];
  onAddProtocol: (p: Omit<Protocol, 'id'>) => void;
  onRemoveProtocol: (id: string) => void;
  onTogglePower: () => void;
  onSearchScriptures: (query: string) => void;
  scriptureResults: ScriptureResult | null;
  isSearchingScriptures: boolean;
  commandLogs: string[];
  systemStats: { power: number; memory: number; logic: number; cpu: number };
  memoryCount: number;
  history: Message[];
  onClearHistory: () => void;
  onDownloadHistory: () => void;
  processes: Process[];
  onKillProcess: (pid: number) => void;
  onImageUpload: (file: File) => void;
  isAnalyzingImage: boolean;
  commandShortcuts: CommandShortcut[];
  onAddShortcut: (s: Omit<CommandShortcut, 'id'>) => void;
  onUpdateShortcut: (s: CommandShortcut) => void;
  onDeleteShortcut: (id: string) => void;
}

const HUD: React.FC<HUDProps> = ({ 
  status, isListening, isMuted, theme, onThemeChange, onToggleMute, transcription, aiResponse, 
  protocols, onAddProtocol, onRemoveProtocol, onTogglePower, scriptureResults, 
  commandLogs, systemStats, processes, onKillProcess, onImageUpload, isAnalyzingImage,
  commandShortcuts, onAddShortcut, onUpdateShortcut, onDeleteShortcut,
  history, onClearHistory, onDownloadHistory, onSearchScriptures, isSearchingScriptures, memoryCount
