      default: return { primary: 'cyan-500', text: 'text-cyan-400', border: 'border-cyan-500', glow: 'rgba(6, 182, 212, 0.4)', bg: 'bg-cyan-500', gradient: 'from-cyan-400 to-blue-600' };
    }
