  const coreCommands = [
    { name: 'OPEN_APP', desc: 'Launches target application.', args: 'target="Name"' },
    { name: 'LIST_PROCESSES', desc: 'Scans and lists active OS tasks.', args: 'target="ALL"' },
    { name: 'KILL_PROCESS', desc: 'Terminates a sub-routine via ID.', args: 'target="PID"' },
    { name: 'SEARCH_SCRIPTURES', desc: 'Consults the Akasha for Vedic verses.', args: 'query="topic"' },
