  const handleShortcutSubmit = () => {
    if (editingShortcut) {
      onUpdateShortcut({ ...editingShortcut, ...shortcutForm });
      setEditingShortcut(null);
    } else {
      onAddShortcut(shortcutForm);
    }
    setShortcutForm({ alias: '', command: '', description: '' });
