  const [isVisionControlActive, setIsVisionControlActive] = useState(false);

  const [commandLogs, setCommandLogs] = useState<string[]>(["Core systems initialized... awaiting boss command."]);
  const [systemStats, setSystemStats] = useState({ power: 88, memory: 45, logic: 95, cpu: 12 });
  const [processes, setProcesses] = useState<Process[]>([
    { pid: 1024, name: 'brahmastra_core.sys', cpu: 2.4, memory: 128, status: 'Running' },
    { pid: 4056, name: 'chrome.exe', cpu: 15.2, memory: 1024, status: 'Running' },
    { pid: 8821, name: 'vscode.exe', cpu: 8.4, memory: 512, status: 'Running' },
    { pid: 9021, name: 'unresponsive_node.exe', cpu: 98.1, memory: 2048, status: 'Critical' },
  ]);

  const [theme, setTheme] = useState<ThemeType>(() => (localStorage.getItem('brahmastra_theme') as ThemeType) || 'Indigo');
  const [history, setHistory] = useState<Message[]>(() => JSON.parse(localStorage.getItem('brahmastra_history') || '[]'));
  const [protocols, setProtocols] = useState<Protocol[]>(() => JSON.parse(localStorage.getItem('brahmastra_protocols') || '[]'));
  const [commandShortcuts, setCommandShortcuts] = useState<CommandShortcut[]>(() => JSON.parse(localStorage.getItem('brahmastra_shortcuts') || '[]'));

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);

  const addLog = useCallback((msg: string) => setCommandLogs(prev => [...prev.slice(-19), msg]), []);

  const stopAudio = useCallback(() => {
    for (const source of sourcesRef.current.values()) { try { source.stop(); } catch (e) {} sourcesRef.current.delete(source); }
    nextStartTimeRef.current = 0;
  }, []);

  const toggleMute = useCallback(() => {
    setIsMuted(prev => {
      const newState = !prev;
      addLog(`SYSTEM: ${newState ? "Muting sub-routines" : "Voice channels unblocked"}.`);
      return newState;
    });
  }, [addLog]);

  // Expose to Python backend via window
  useEffect(() => {
    (window as any).brahmastra_uplink = {
      toggleMute: toggleMute,
      addLog: addLog
    };
  }, [toggleMute, addLog]);

  const disconnect = useCallback(() => {
    if (sessionRef.current) {
      if (typeof sessionRef.current.close === 'function') {
        sessionRef.current.close();
      }
    }
    stopAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsListening(false);
    sessionRef.current = null;
    addLog("SYSTEM: Uplink terminated. Brahmastra Offline.");
  }, [stopAudio, addLog]);

  const connect = useCallback(async () => {
    if (sessionRef.current) return;
    setStatus(ConnectionStatus.CONNECTING);
    addLog("SYSTEM: Establishing secure encrypted channel...");

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      gainNodeRef.current = outputAudioContextRef.current.createGain();
      gainNodeRef.current.connect(outputAudioContextRef.current.destination);

      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: SYSTEM_INSTRUCTION_BASE,
          tools: [{ googleSearch: {} }, { functionDeclarations: [SYSTEM_COMMAND_TOOL, SEARCH_SCRIPTURES_TOOL] }],
          outputAudioTranscription: {},
          inputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            setIsListening(true);
            addLog("SYSTEM: Uplink established. Brahmastra Online.");
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (isMuted) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(session => session.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(gainNodeRef.current!);
              source.onended = () => sourcesRef.current.delete(source);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }
            if (message.serverContent?.inputTranscription) {
              setTranscription(message.serverContent.inputTranscription.text);
            }
            if (message.serverContent?.outputTranscription) {
              setAiResponse(message.serverContent.outputTranscription.text);
            }
            if (message.serverContent?.interrupted) stopAudio();
          },
          onerror: () => setStatus(ConnectionStatus.ERROR),
          onclose: () => { setStatus(ConnectionStatus.DISCONNECTED); setIsListening(false); sessionRef.current = null; }
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) { setStatus(ConnectionStatus.ERROR); }
  }, [addLog, isMuted, stopAudio]);

  useEffect(() => {
    localStorage.setItem('brahmastra_protocols', JSON.stringify(protocols));
    localStorage.setItem('brahmastra_history', JSON.stringify(history));
    localStorage.setItem('brahmastra_theme', theme);
    localStorage.setItem('brahmastra_shortcuts', JSON.stringify(commandShortcuts));
  }, [protocols, history, theme, commandShortcuts]);

  const handleImageUpload = async (file: File) => {
    setIsAnalyzingImage(true);
    addLog(`SYSTEM: Scanning visual data package: ${file.name}...`);
    try {
      const reader = new FileReader();
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(file);
      });
      const base64 = await base64Promise;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: {
          parts: [
            { inlineData: { data: base64, mimeType: file.type } },
            { text: "Analyze this image with high-level military-grade sensors. Explain what you see in Hinglish." }
          ]
        }
      });
      setAiResponse(response.text || "Encryption failed.");
    } catch (err) {
      addLog("CRITICAL: Vision sensor malfunction.");
    } finally {
      setIsAnalyzingImage(false);
    }
  };

  return (
    <div className="h-screen w-screen bg-slate-950 overflow-hidden relative">
      <HUD 
        status={status}
        isListening={isListening}
        isMuted={isMuted}
        theme={theme}
        onThemeChange={setTheme}
        onToggleMute={toggleMute}
        transcription={transcription}
        aiResponse={aiResponse}
        protocols={protocols}
        onAddProtocol={(p) => setProtocols(prev => [...prev, { ...p, id: Date.now().toString() }])}
        onRemoveProtocol={(id) => setProtocols(prev => prev.filter(p => p.id !== id))}
        onTogglePower={() => status === ConnectionStatus.CONNECTED ? disconnect() : connect()}
        onSearchScriptures={() => {}} 
        scriptureResults={scriptureResults}
        isSearchingScriptures={isSearchingScriptures}
        commandLogs={commandLogs}
        systemStats={systemStats}
        memoryCount={0}
        history={history}
        onClearHistory={() => setHistory([])}
        onDownloadHistory={() => {}}
        processes={processes}
        onKillProcess={(pid) => setProcesses(prev => prev.filter(p => p.pid !== pid))}
        onImageUpload={handleImageUpload}
        isAnalyzingImage={isAnalyzingImage}
        commandShortcuts={commandShortcuts}
        onAddShortcut={(s) => setCommandShortcuts(prev => [...prev, { ...s, id: Date.now().toString() }])}
        onUpdateShortcut={(s) => setCommandShortcuts(prev => prev.map(item => item.id === s.id ? s : item))}
        onDeleteShortcut={(id) => setCommandShortcuts(prev => prev.filter(s => s.id !== id))}
        onToggleVision={() => setIsVisionControlActive(prev => !prev)}
        isVisionActive={isVisionControlActive}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ConnectionStatus, Protocol, ScriptureResult, Message, ThemeType, Process, CommandShortcut } from '../types';

interface HUDProps {
  status: ConnectionStatus;
  isListening: boolean;
  isMuted: boolean;
  theme: ThemeType;
  onThemeChange: (theme: ThemeType) => void;
  onToggleMute: () => void;
  transcription: string;
  aiResponse: string;
  protocols: Protocol[];
  onAddProtocol: (p: Omit<Protocol, 'id'>) => void;
  onRemoveProtocol: (id: string) => void;
  onTogglePower: () => void;
  onSearchScriptures: (query: string) => void;
  scriptureResults: ScriptureResult | null;
  isSearchingScriptures: boolean;
  commandLogs: string[];
  systemStats: { power: number; memory: number; logic: number; cpu: number };
  memoryCount: number;
  history: Message[];
  onClearHistory: () => void;
  onDownloadHistory: () => void;
  processes: Process[];
  onKillProcess: (pid: number) => void;
  onImageUpload: (file: File) => void;
  isAnalyzingImage: boolean;
  commandShortcuts: CommandShortcut[];
  onAddShortcut: (s: Omit<CommandShortcut, 'id'>) => void;
  onUpdateShortcut: (s: CommandShortcut) => void;
  onDeleteShortcut: (id: string) => void;
  onToggleVision: () => void;
  isVisionActive: boolean;
}

