  protocols, onRemoveProtocol, onTogglePower, scriptureResults, 
  commandLogs, processes, onKillProcess, onImageUpload, isAnalyzingImage,
  commandShortcuts, onAddShortcut, onUpdateShortcut, onDeleteShortcut,
